const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const bcrypt = require('bcryptjs');
const expressSession = require('express-session');

const app = express();
const server = http.createServer(app);
const io = socketIO(server);

app.use(express.json());
app.use(expressSession({
  secret: 'your_secret',
  resave: false,
  saveUninitialized: true
}));

let users = {
  'user1': '$2a$08$GVY6Oh3k9hJxQyvgDnXKSeU/4bZC.E8lWo5qJtFg6r/c7PpT2k7mS' // hashed password for user1
};

app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.sendStatus(401);

  if (users[username]) {
    bcrypt.compare(password, users[username], (err, result) => {
      if (result) return res.status(200).json({ status: 'success', username });
      else return res.sendStatus(401);
    });
  } else return res.sendStatus(401);
});

io.on('connection', (socket) => {
  socket.on('/login', (data, callback) => {
    app.post('/login', data, (err, result) => {
      if (!err && result.status === 'success') {
        socket.sessionStore.create(socket.request.session, (err) => {
          if (err) throw err;
          socket.request.session.user = result.username;
          callback(null, true);
        });
      } else callback(result || err);
    });
  });

  socket.on('/join', ({ username, score }) => {
    if (!socket.sessionStore.session) return socket.emit('loginError', 'Not authenticated');
    const { user } = socket.sessionStore.session;

    // Trust client-reported scores and update our database or leaderboard here
    console.log(`${user} joined with score ${score}`);
  });
});

server.listen(3000, () => console.log('Server listening on port 3000'));